import { Router } from 'express';
import { createWorkspace, renameWorkspace, deleteWorkspace, getWorkspaces, getWorkspaceById } from '../controllers/workspace.controller.js';
import { verifyToken } from '../middleware/verifyToken.js';
const router = Router();
router.use(verifyToken);
router.post('/create', createWorkspace);
router.put('/:id/rename', renameWorkspace);
router.delete('/:id/delete', deleteWorkspace);
router.get('/', getWorkspaces);
router.get('/:id', getWorkspaceById);
export default router;
